// Discriminated Union Pattern
type Shape = 
    | { kind: "circle"; radius: number }
    | { kind: "rectangle"; width: number; height: number }
    | { kind: "square"; size: number };

function getArea(shape: Shape): number {
    switch (shape.kind) {
        case "circle":
            return Math.PI * shape.radius ** 2;
        case "rectangle":
            return shape.width * shape.height;
        case "square":
            return shape.size ** 2;
        default:
            // Exhaustiveness check with never
            const _exhaustiveCheck: never = shape;
            return _exhaustiveCheck;
    }
}

// Usage with type safety
const circle: Shape = { kind: "circle", radius: 5 };
console.log(getArea(circle)); // 78.54

// Type Guards with User-Defined Functions
interface User {
    id: number;
    name: string;
    email: string;
}

interface Admin {
    id: number;
    name: string;
    permissions: string[];
}

type Account = User | Admin;

// Type guard functions
function isUser(account: Account): account is User {
    return (account as User).email !== undefined;
}

function isAdmin(account: Account): account is Admin {
    return (account as Admin).permissions !== undefined;
}

// Usage with type narrowing
function processAccount(account: Account) {
    if (isUser(account)) {
        // TypeScript knows account is User here
        console.log(`User email: ${account.email}`);
    } else if (isAdmin(account)) {
        // TypeScript knows account is Admin here
        console.log(`Admin permissions: ${account.permissions.join(', ')}`);
    }
}

// Runtime validation with type guards
function validateAccount(data: unknown): Account | null {
    if (typeof data !== 'object' || data === null) return null;

    const obj = data as Record<string, unknown>;

    if (typeof obj.id === 'number' && typeof obj.name === 'string') {
        if (typeof obj.email === 'string') {
            return { id: obj.id, name: obj.name, email: obj.email };
        }
        if (Array.isArray(obj.permissions)) {
            return { id: obj.id, name: obj.name, permissions: obj.permissions as string[] };
        }
    }

    return null;
}

// Const Assertions and Immutable Patterns
// Deep readonly with const assertion
const APP_CONFIG = {
    api: {
        baseUrl: "https://api.example.com",
        endpoints: {
            users: "/users",
            posts: "/posts"
        }
    },
    features: {
        darkMode: true,
        notifications: false
    }
} as const;

// Type inference from const assertion
type AppConfig = typeof APP_CONFIG;
// Equivalent to:
// type AppConfig = {
//     readonly api: {
//         readonly baseUrl: "https://api.example.com";
//         readonly endpoints: {
//             readonly users: "/users";
//             readonly posts: "/posts";
//         };
//     };
//     readonly features: {
//         readonly darkMode: true;
//         readonly notifications: false;
//     };
// }

// Readonly array with const assertion
const COLORS = ["red", "green", "blue"] as const;
type Color = typeof COLORS[number]; // "red" | "green" | "blue"

// Immutable tuple with const assertion
const POINT = [10, 20] as const; // readonly [10, 20]

// Function that accepts readonly parameters
function calculateDistance(
    p1: readonly [number, number],
    p2: readonly [number, number]
): number {
    const [x1, y1] = p1;
    const [x2, y2] = p2;
    return Math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2);
}

// Usage - prevents mutation
// calculateDistance(POINT, [5, 5]); // Works
// POINT[0] = 15; // Error: Cannot assign to '0' because it is a read-only property

