// Advanced Union & Intersection Patterns

// Union to Intersection transformation
type UnionToIntersection<U> = 
  (U extends any ? (k: U) => void : never) extends ((k: infer I) => void) 
    ? I 
    : never;

// Example usage
type ExampleUnion = { a: string } | { b: number };
type ExampleIntersection = UnionToIntersection<ExampleUnion>;
// Result: { a: string } & { b: number }

// Filtering Union Types
type Filter<T, U> = T extends U ? T : never;
type NumbersOnly = Filter<string | number | boolean, number>; // number

// Extracting specific union members
type ExtractString<T> = Extract<T, string>;
type ExtractFunction<T> = Extract<T, Function>;

// Conditional type distribution
type Box<T> = T extends any ? { value: T } : never;
type StringOrNumberBox = Box<string | number>;
// Result: { value: string } | { value: number }

// Optional Pattern with Discriminated Union
type Result<T, E = Error> =
  | { success: true; data: T }
  | { success: false; error: E };

function fetchData(): Result<string> {
  try {
    const data = "fetched data";
    return { success: true, data };
  } catch (error) {
    return { success: false, error: error as Error };
  }
}

// Usage with type safety
const result = fetchData();
if (result.success) {
  console.log(result.data); // string
} else {
  console.error(result.error); // Error
}

// State Machine Pattern
type State =
  | { status: 'idle' }
  | { status: 'loading'; requestId: string }
  | { status: 'success'; data: any }
  | { status: 'error'; error: string };

function transition(current: State, action: string): State {
  switch (current.status) {
    case 'idle':
      if (action === 'FETCH') {
        return { status: 'loading', requestId: 'req-123' };
      }
      return current;
    case 'loading':
      if (action === 'SUCCESS') {
        return { status: 'success', data: {} };
      }
      if (action === 'ERROR') {
        return { status: 'error', error: 'Failed' };
      }
      return current;
    default:
      return current;
  }
}

// Complex Type Guards and Control Flow

// Recursive Type Guard for nested structures
interface TreeNode {
  value: number;
  children?: TreeNode[];
}

function isTreeNode(value: unknown): value is TreeNode {
  if (!value || typeof value !== 'object') return false;

  const obj = value as Record<string, unknown>;

  // Check value property
  if (typeof obj.value !== 'number') return false;

  // Check children property (optional)
  if ('children' in obj) {
    if (!Array.isArray(obj.children)) return false;

    // Recursively check all children
    return obj.children.every(isTreeNode);
  }

  return true;
}

// Type guard composition
function isStringOrNumber(value: unknown): value is string | number {
  return typeof value === 'string' || typeof value === 'number';
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === 'string' && value.length > 0;
}

// Complex validation with multiple guards
function validateUser(input: unknown): input is { name: string; age: number } {
  if (!input || typeof input !== 'object') return false;

  const obj = input as Record<string, unknown>;

  return (
    typeof obj.name === 'string' &&
    obj.name.length > 0 &&
    typeof obj.age === 'number' &&
    obj.age >= 0 &&
    obj.age <= 150
  );
}

// Control flow with assertion functions
class AssertionError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'AssertionError';
  }
}

function assert(condition: any, message?: string): asserts condition {
  if (!condition) {
    throw new AssertionError(message || 'Assertion failed');
  }
}

function assertIsArray(value: unknown): asserts value is any[] {
  assert(Array.isArray(value), 'Value must be an array');
}

function assertIsDefined<T>(value: T): asserts value is NonNullable<T> {
  assert(value != null, 'Value must be defined');
}

// Usage example
function processData(data: unknown) {
  assertIsDefined(data);
  assert(typeof data === 'object');

  const obj = data as Record<string, unknown>;

  if ('items' in obj) {
    assertIsArray(obj.items);

    // Now TypeScript knows obj.items is any[]
    obj.items.forEach(item => {
      console.log(item);
    });
  }
}

// Type narrowing with custom predicates
type ApiResponse<T> = 
  | { status: 'success'; data: T; timestamp: Date }
  | { status: 'error'; message: string; code: number };

function isSuccessResponse<T>(response: ApiResponse<T>): response is ApiResponse<T> & { status: 'success' } {
  return response.status === 'success';
}

// Usage
const response: ApiResponse<string> = { 
  status: 'success', 
  data: 'result', 
  timestamp: new Date() 
};

if (isSuccessResponse(response)) {
  // TypeScript knows response.data exists
  console.log(response.data);
}

// Branded Types and Opaque Type Patterns

// Base branded type helper
type Brand<T, B> = T & { readonly __brand: B };

// Application-specific branded types
type Email = Brand<string, 'Email'>;
type UserId = Brand<number, 'UserId'>;
type OrderId = Brand<string, 'OrderId'>;
type Currency = Brand<number, 'Currency'>;

// Constructor functions with validation
function createEmail(value: string): Email {
  // Email validation logic
  if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value)) {
    throw new Error('Invalid email format');
  }
  return value as Email;
}

function createUserId(value: number): UserId {
  if (value <= 0) {
    throw new Error('User ID must be positive');
  }
  return value as UserId;
}

// Usage with type safety
const email: Email = createEmail('user@example.com');
const userId: UserId = createUserId(123);

// These will cause type errors:
// const wrongEmail: Email = 'not-an-email'; // Error
// const wrongId: UserId = 456; // Error (needs constructor)

// Opaque types for measurement units
type Meters = Brand<number, 'Meters'>;
type Seconds = Brand<number, 'Seconds'>;
type Kilograms = Brand<number, 'Kilograms'>;

// Type-safe arithmetic operations
function addMeters(a: Meters, b: Meters): Meters {
  return (a + b) as Meters;
}

function multiplyMeters(m: Meters, factor: number): Meters {
  return (m * factor) as Meters;
}

// Prevents incorrect operations
const distance1: Meters = 10 as Meters;
const distance2: Meters = 20 as Meters;
const total = addMeters(distance1, distance2); // OK

// const time: Seconds = 5 as Seconds;
// addMeters(distance1, time); // Type error!

// Database ID patterns
type EntityId<T extends string> = Brand<string, T>;

type ProductId = EntityId<'Product'>;
type CategoryId = EntityId<'Category'>;
type CustomerId = EntityId<'Customer'>;

// Type-safe repository pattern
interface Repository<T, ID> {
  findById(id: ID): Promise<T | null>;
  save(entity: T): Promise<ID>;
}

class ProductRepository implements Repository<Product, ProductId> {
  async findById(id: ProductId): Promise<Product | null> {
    // Implementation
    return null;
  }

  async save(product: Product): Promise<ProductId> {
    // Implementation
    return 'product-123' as ProductId;
  }
}

// Prevents ID mixing
const productRepo = new ProductRepository();
const productId: ProductId = 'prod-1' as ProductId;
const categoryId: CategoryId = 'cat-1' as CategoryId;

// productRepo.findById(categoryId); // Type error!
// productRepo.findById(productId); // OK

// Runtime validation with branded types
function validateAndBrand<T, B>(
  value: unknown,
  validator: (val: unknown) => boolean,
  errorMessage: string
): Brand<T, B> {
  if (!validator(value)) {
    throw new Error(errorMessage);
  }
  return value as Brand<T, B>;
}

// Example usage
type PositiveNumber = Brand<number, 'Positive'>;

function createPositiveNumber(value: unknown): PositiveNumber {
  return validateAndBrand<number, 'Positive'>(
    value,
    (val) => typeof val === 'number' && val > 0,
    'Value must be a positive number'
  );
}

