// Advanced Mapped Types with Key Remapping and Conditional Logic

// 1. Filter properties by type
type FilterByType<T, U> = {
    [K in keyof T as T[K] extends U ? K : never]: T[K]
};

interface MixedObject {
    id: number;
    name: string;
    age: number;
    email: string;
    active: boolean;
}

type StringProperties = FilterByType<MixedObject, string>;
// Result: { name: string; email: string }

type NumberProperties = FilterByType<MixedObject, number>;
// Result: { id: number; age: number }

// 2. Create getter methods from properties
type Getters<T> = {
    [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K]
};

interface Person {
    name: string;
    age: number;
    email: string;
}

type PersonGetters = Getters<Person>;
// Result: {
//   getName: () => string;
//   getAge: () => number;
//   getEmail: () => string;
// }

// 3. Transform property names (camelCase to snake_case)
type CamelToSnake<S extends string> = 
    S extends `${infer T}${infer U}`
    ? `${T extends Lowercase<T> ? T : `_${Lowercase<T>}`}${CamelToSnake<U>}`
    : S;

type SnakeCase<T> = {
    [K in keyof T as CamelToSnake<string & K>]: T[K]
};

type SnakePerson = SnakeCase<Person>;
// Result: { name: string; age: number; email: string } 
// (no change as already lowercase, but works with mixedCase)

// 4. Conditional property transformation based on value type
type TransformProperties<T> = {
    [K in keyof T]: T[K] extends string
        ? `prefix_${T[K]}`
        : T[K] extends number
        ? T[K] extends 0 ? 'zero' : 'non-zero'
        : T[K];
};

interface Sample {
    title: string;
    count: number;
    isActive: boolean;
}

type Transformed = TransformProperties<Sample>;
// Result: {
//   title: `prefix_${string}`;
//   count: 'zero' | 'non-zero';
//   isActive: boolean;
// }

// 5. Create type-safe event system
type EventMap = {
    click: { x: number; y: number };
    hover: { element: string; duration: number };
    submit: { form: string; data: Record<string, unknown> };
};

type EventHandlers = {
    [K in keyof EventMap as `on${Capitalize<K>}`]: (event: EventMap[K]) => void
};

// Implementation
const handlers: EventHandlers = {
    onClick: (event) => console.log(`Clicked at ${event.x}, ${event.y}`),
    onHover: (event) => console.log(`Hovered ${event.element} for ${event.duration}ms`),
    onSubmit: (event) => console.log(`Submitted form ${event.form}`)
    // TypeScript ensures correct parameter types for each handler
};

// 6. Deep readonly with conditional recursion
type DeepReadonly<T> = T extends object
    ? { readonly [K in keyof T]: DeepReadonly<T[K]> }
    : T;

interface NestedObject {
    a: {
        b: {
            c: number;
            d: string[];
        };
        e: boolean;
    };
    f: number;
}

type ReadonlyNested = DeepReadonly<NestedObject>;
// All properties at all levels are readonly

// 7. Type-safe builder pattern
type Builder<T, K extends keyof T = keyof T> = 
    K extends keyof T
    ? (value: T[K]) => Builder<Omit<T, K>> & { build(): T }
    : { build(): T };

function createBuilder<T>(): Builder<T> {
    const obj = {} as T;
    const builder = new Proxy({} as any, {
        get(target, prop: string) {
            if (prop === 'build') {
                return () => obj;
            }
            return (value: any) => {
                (obj as any)[prop] = value;
                return builder;
            };
        }
    });
    return builder;
}

// Usage
interface Product {
    id: number;
    name: string;
    price: number;
}

const productBuilder = createBuilder<Product>();
const product = productBuilder
    .id(1)
    .name('Laptop')
    .price(999)
    .build(); // Type-safe with all required properties

// Complex Conditional Types and Type-Level Programming

// 1. Recursive type unwrapping
type DeepUnwrap<T> = 
    T extends Promise<infer U>
    ? DeepUnwrap<U>
    : T extends Array<infer U>
    ? DeepUnwrap<U>[]
    : T extends object
    ? { [K in keyof T]: DeepUnwrap<T[K]> }
    : T;

// Example: deeply unwrap promises and arrays
type ComplexType = Promise<Array<Promise<{ value: number }>>>;
type Unwrapped = DeepUnwrap<ComplexType>;
// Result: { value: number }[]

// 2. Type-safe function composition
type Compose<Fns extends Array<(arg: any) => any>> = 
    Fns extends []
    ? (arg: never) => never
    : Fns extends [(arg: infer A) => infer B]
    ? (arg: A) => B
    : Fns extends [(...args: infer Args) => infer Result, ...infer Rest]
    ? Rest extends Array<(arg: any) => any>
        ? (arg: Args) => Compose<Rest> extends (arg: any) => infer FinalResult
            ? FinalResult
            : never
        : never
    : never;

// Usage
const add = (x: number) => x + 1;
const multiply = (x: number) => x * 2;
const toString = (x: number) => x.toString();

type Composed = Compose<[typeof add, typeof multiply, typeof toString]>;
// Result: (arg: number) => string

// 3. Tuple manipulation at type level
type Head<T extends any[]> = T extends [infer H, ...any[]] ? H : never;
type Tail<T extends any[]> = T extends [any, ...infer R] ? R : never;
type Last<T extends any[]> = T extends [...any[], infer L] ? L : never;

// Zip two tuples
type Zip<A extends any[], B extends any[]> = 
    A extends [infer HA, ...infer TA]
    ? B extends [infer HB, ...infer TB]
        ? [[HA, HB], ...Zip<TA, TB>]
        : []
    : [];

type Zipped = Zip<[1, 2, 3], ['a', 'b', 'c']>;
// Result: [[1, 'a'], [2, 'b'], [3, 'c']]

// 4. Type-level arithmetic (limited)
type Length<T extends any[]> = T['length'];
type Push<T extends any[], V> = [...T, V];
type Concat<A extends any[], B extends any[]> = [...A, ...B];

type Tuple1 = [1, 2, 3];
type Len1 = Length<Tuple1>; // 3
type Tuple2 = Push<Tuple1, 4>; // [1, 2, 3, 4]
type Tuple3 = Concat<Tuple1, Tuple2>; // [1, 2, 3, 1, 2, 3, 4]

// 5. Pattern matching with template literal types
type ParseRoute<Route extends string> = 
    Route extends `${infer Start}/:${infer Param}/${infer Rest}`
    ? { param: Param; rest: ParseRoute<`/${Rest}`> }
    : Route extends `${infer Start}/:${infer Param}`
    ? { param: Param }
    : {};

type RouteParams = ParseRoute<'/users/:id/posts/:postId'>;
// Result: { param: 'id'; rest: { param: 'postId' } }

// 6. Type-safe validation schema
type Validator<T> = (value: unknown) => value is T;

interface Schema {
    [key: string]: Validator<any>;
}

type InferSchema<S extends Schema> = {
    [K in keyof S]: S[K] extends Validator<infer T> ? T : never
};

const stringValidator: Validator<string> = (v): v is string => typeof v === 'string';
const numberValidator: Validator<number> = (v): v is number => typeof v === 'number';
const arrayValidator = <T>(itemValidator: Validator<T>): Validator<T[]> => 
    (v): v is T[] => Array.isArray(v) && v.every(itemValidator);

const userSchema = {
    name: stringValidator,
    age: numberValidator,
    tags: arrayValidator(stringValidator)
} as const;

type User = InferSchema<typeof userSchema>;
// Result: { name: string; age: number; tags: string[] }

// 7. Advanced conditional type: Get nested property type
type GetProp<T, Path extends string> = 
    Path extends `${infer Key}.${infer Rest}`
    ? Key extends keyof T
        ? GetProp<T[Key], Rest>
        : never
    : Path extends keyof T
    ? T[Path]
    : never;

interface Complex {
    user: {
        profile: {
            name: string;
            address: {
                street: string;
                city: string;
            };
        };
    };
}

type StreetName = GetProp<Complex, 'user.profile.address.street'>; // string
type Profile = GetProp<Complex, 'user.profile'>; // { name: string; address: { ... } }

// 8. Type-safe router with parameter extraction
type ExtractParams<Route extends string> = 
    Route extends `${string}:${infer Param}/${infer Rest}`
    ? { [K in Param | keyof ExtractParams<`/${Rest}`>]: string }
    : Route extends `${string}:${infer Param}`
    ? { [K in Param]: string }
    : {};

function createRoute<Route extends string>(route: Route) {
    return {
        match(path: string): ExtractParams<Route> | null {
            // Implementation would parse path and extract params
            return null;
        },
        build(params: ExtractParams<Route>): string {
            // Implementation would build path from params
            return '';
        }
    };
}

const userRoute = createRoute('/users/:userId/posts/:postId');
type UserRouteParams = Parameters<typeof userRoute.build>[0];
// Result: { userId: string; postId: string }

// Template Literal Types and String Manipulation

// 1. Basic template literal patterns
type HttpMethod = 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
type ApiEndpoint = `${Lowercase<HttpMethod>} /api/${string}`;

type EventType = 'click' | 'hover' | 'focus' | 'blur';
type EventHandlerName = `on${Capitalize<EventType>}`;
// Result: 'onClick' | 'onHover' | 'onFocus' | 'onBlur'

// 2. String splitting and joining
type Split<S extends string, D extends string> = 
    S extends `${infer T}${D}${infer U}`
    ? [T, ...Split<U, D>]
    : [S];

type PathParts = Split<'users/posts/comments', '/'>;
// Result: ['users', 'posts', 'comments']

type Join<T extends string[], D extends string> = 
    T extends [infer F, ...infer R]
    ? F extends string
        ? R extends string[]
            ? `${F}${D}${Join<R, D>}`
            : F
        : never
    : '';

type JoinedPath = Join<['users', 'posts', 'comments'], '/'>;
// Result: 'users/posts/comments'

// 3. String case conversion
type CamelToKebab<S extends string> = 
    S extends `${infer T}${infer U}`
    ? `${T extends Lowercase<T> ? T : `-${Lowercase<T>}`}${CamelToKebab<U>}`
    : S;

type KebabToCamel<S extends string> = 
    S extends `${infer T}-${infer U}`
    ? `${T}${Capitalize<KebabToCamel<U>>}`
    : S;

type PascalToCamel<S extends string> = 
    S extends `${infer First}${infer Rest}`
    ? `${Lowercase<First>}${Rest}`
    : S;

// Examples
type KebabCase = CamelToKebab<'backgroundColor'>; // 'background-color'
type CamelCase = KebabToCamel<'background-color'>; // 'backgroundColor'
type PascalCase = Capitalize<'backgroundColor'>; // 'BackgroundColor'

// 4. Pattern validation with template literals
type EmailPattern = `${string}@${string}.${string}`;
type HexColor = `#${string}`;
type UUID = `${string}-${string}-${string}-${string}-${string}`;

type ValidateEmail<Email extends string> = 
    Email extends EmailPattern ? Email : never;

type ValidEmail = ValidateEmail<'user@example.com'>; // 'user@example.com'
type InvalidEmail = ValidateEmail<'not-an-email'>; // never

// 5. Dynamic CSS property generation
type CssProperty = 'color' | 'background-color' | 'font-size' | 'margin' | 'padding';
type CssValue = string | number;

type CssDeclaration = `${CssProperty}: ${CssValue}`;
type CssRule = `${string} { ${CssDeclaration}; }`;

// 6. Type-safe internationalization keys
type Locale = 'en' | 'fr' | 'de' | 'es';
type TranslationKey = `${Locale}.${string}.${string}`;

type Translations = {
    [K in TranslationKey]: string;
};

const translations: Translations = {
    'en.welcome.greeting': 'Hello',
    'en.welcome.message': 'Welcome to our app',
    'fr.welcome.greeting': 'Bonjour',
    'fr.welcome.message': 'Bienvenue sur notre application'
    // TypeScript ensures all keys follow the pattern
};

// 7. API route generation with parameter inference
type RouteWithParams<Path extends string> = 
    Path extends `${infer Start}:${infer Param}/${infer Rest}`
    ? `${Start}${string}/${RouteWithParams<Rest>}`
    : Path extends `${infer Start}:${infer Param}`
    ? `${Start}${string}`
    : Path;

function createApiRoute<Path extends string>(path: Path) {
    return {
        path,
        // The URL pattern with string placeholders for params
        pattern: path.replace(/:(\w+)/g, '([^/]+)') as RouteWithParams<Path>,
        // Extract params from a matching URL
        extractParams(url: string): Record<string, string> | null {
            const match = url.match(new RegExp(this.pattern));
            if (!match) return null;

            const paramNames = (path.match(/:(\w+)/g) || []).map(p => p.slice(1));
            const params: Record<string, string> = {};
            paramNames.forEach((name, i) => {
                params[name] = match[i + 1];
            });
            return params;
        }
    };
}

const userRoute = createApiRoute('/users/:userId/posts/:postId');
const params = userRoute.extractParams('/users/123/posts/456');
// params: { userId: '123', postId: '456' }

// 8. String transformation chain
type TransformChain<S extends string> = 
    S extends `${infer First}${infer Rest}`
    ? `${Uppercase<First>}${Lowercase<Rest>}`
    : S;

type Trim<S extends string> = 
    S extends ` ${infer T}` ? Trim<T> :
    S extends `${infer T} ` ? Trim<T> :
    S;

type ProcessString<S extends string> = TransformChain<Trim<S>>;

type Processed = ProcessString<'  hello world  '>; // 'HELLO WORLD'

