// Complete Node.js TypeScript Server Example
import express, { Application, Request, Response, NextFunction } from 'express';
import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';

// Type-safe environment configuration
interface AppConfig {
  port: number;
  nodeEnv: 'development' | 'production' | 'test';
  apiPrefix: string;
}

function loadConfig(): AppConfig {
  const port = parseInt(process.env.PORT || '3000');
  const nodeEnv = (process.env.NODE_ENV || 'development') as AppConfig['nodeEnv'];

  return {
    port,
    nodeEnv,
    apiPrefix: '/api/v1'
  };
}

// Typed data model
interface User {
  id: string;
  name: string;
  email: string;
  createdAt: Date;
}

// Type-safe service layer
class UserService {
  private usersFile = join(__dirname, 'data', 'users.json');

  getAllUsers(): User[] {
    try {
      const data = readFileSync(this.usersFile, 'utf-8');
      return JSON.parse(data) as User[];
    } catch (error) {
      return [];
    }
  }

  addUser(user: Omit<User, 'id' | 'createdAt'>): User {
    const users = this.getAllUsers();
    const newUser: User = {
      ...user,
      id: Date.now().toString(),
      createdAt: new Date()
    };

    users.push(newUser);
    writeFileSync(this.usersFile, JSON.stringify(users, null, 2));

    return newUser;
  }
}

// Express app with TypeScript
const app: Application = express();
const config = loadConfig();
const userService = new UserService();

// Middleware typing
app.use(express.json());

// Type-safe route handlers
app.get(`${config.apiPrefix}/users`, (req: Request, res: Response) => {
  const users = userService.getAllUsers();
  res.json({ success: true, data: users });
});

app.post(`${config.apiPrefix}/users`, (req: Request, res: Response) => {
  try {
    const { name, email } = req.body;

    if (!name || !email) {
      return res.status(400).json({ 
        success: false, 
        error: 'Name and email are required' 
      });
    }

    const user = userService.addUser({ name, email });
    res.status(201).json({ success: true, data: user });
  } catch (error) {
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

// Error handling middleware
app.use((err: Error, req: Request, res: Response, next: NextFunction) => {
  console.error('Error:', err);
  res.status(500).json({ success: false, error: 'Something went wrong' });
});

